import { isUndefined } from 'lodash-es';

import {
  DOWNWARD_ICON_DEFAULT_COLOR,
  DOWNWARD_VALUE_DEFAULT_COLOR,
  NEUTRAL_ICON_DEFAULT_COLOR,
  NEUTRAL_VALUE_DEFAULT_COLOR,
  UPWARD_ICON_DEFAULT_COLOR,
  UPWARD_VALUE_DEFAULT_COLOR,
} from '../../../constants.js';
import type { InverseTrendOptions } from '../types/inverse-trend-options.js';
import type { TrendColorsConfig } from '../types/trend-color-config.js';
import type { TrendDirection } from '../types/trend-direction.js';
import type { TrendIndicatorColors } from '../types/trend-indicator-colors.js';

const UPWARD_COLORS: [string, string] = [
  UPWARD_ICON_DEFAULT_COLOR,
  UPWARD_VALUE_DEFAULT_COLOR,
];
const NEUTRAL_COLORS: [string, string] = [
  NEUTRAL_ICON_DEFAULT_COLOR,
  NEUTRAL_VALUE_DEFAULT_COLOR,
];
const DOWNWARD_COLORS: [string, string] = [
  DOWNWARD_ICON_DEFAULT_COLOR,
  DOWNWARD_VALUE_DEFAULT_COLOR,
];

const DEFAULT_TREND = {
  downward: DOWNWARD_COLORS,
  neutral: NEUTRAL_COLORS,
  upward: UPWARD_COLORS,
};

const INVERSE_TREND = {
  downward: UPWARD_COLORS,
  neutral: NEUTRAL_COLORS,
  upward: DOWNWARD_COLORS,
};

/**
 * Defines which color corresponds at a given time to the Icon and the Value,
 * taking into account the direction, the colors override and if the trend behavior is inverted
 *
 * @param direction -
 * @param inverseTrend -
 * @param colorsOverride -
 */
export const defineTrendColors = (
  direction: TrendDirection,
  inverseTrend: InverseTrendOptions,
  colorsOverride?: Partial<TrendIndicatorColors>,
): [string, string] => {
  const trendColors: TrendColorsConfig =
    inverseTrend === 'color' ? { ...INVERSE_TREND } : { ...DEFAULT_TREND };

  if (!isUndefined(colorsOverride)) {
    Object.keys(colorsOverride).forEach((key: string) => {
      const trendDirection = key as TrendDirection;

      if (!isUndefined(colorsOverride[trendDirection])) {
        trendColors[trendDirection] = [
          // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
          colorsOverride[trendDirection]!,
          // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
          colorsOverride[trendDirection]!,
        ];
      }
    });
  }

  return trendColors[direction];
};
